@@ -0,0 +1,7 @@
+{
+  "protoc": {
+    "options": [
+      "-Iproto"
+    ]
+  }
+}
\ No newline at end of file

@@ -0,0 +1,15 @@
+syntax = "proto3";
+
+import "unknown.proto";
+import "ok.proto";
+import "warning.proto";
+import "error.proto";
+
+message DiagStatus {
+  oneof status {
+    Unknown unknown = 1;
+    Ok ok = 2;
+    Warning warning = 3;
+    Error error = 4;
+  }
+}
\ No newline at end of file

@@ -0,0 +1,19 @@
+syntax = "proto3";
+
+import "diag_status.proto";
+
+message DiagTree {
+  message DiagList {
+    repeated DiagTree list = 1;
+  }
+
+  message DiagMap {
+    map<string, DiagTree> map = 1;
+  }
+
+  oneof tree {
+    DiagStatus status = 1;
+    DiagList list = 2;
+    DiagMap map = 3;
+  }
+}
\ No newline at end of file

@@ -0,0 +1,5 @@
+syntax = "proto3";
+
+message Error {
+  string msg = 1;
+}
\ No newline at end of file

@@ -0,0 +1,5 @@
+syntax = "proto3";
+
+message Ok {
+  optional string msg = 1;
+}
\ No newline at end of file

@@ -0,0 +1,5 @@
+syntax = "proto3";
+
+message Unknown {
+  optional string msg = 1;
+}
\ No newline at end of file

